package pkg;
import "DPI-C" context function chandle dpi_func(input int a);
endpackage

function chandle dpi_wrap(input int a);
return dpi_func(a);
endfunction

function py_object get_item(int idx);
py_object ret = new(dpi_wrap(idx));
return ret;
endfunction

class py_tuple;
function py_object get_item(int idx);
return new(pkg_dpi_func(idx));
endfunction
endclass
